set-variable.value:
#[%dw 2.0
output application/java

var data = if (payload is Array) payload[0] else payload

fun getVal(v) =
    if (v is Array) v[0]
    else v default ""

---
"<!DOCTYPE html>

<html>

<head>

<meta charset='UTF-8'>

<style>

body{
    margin:0;
    padding:40px 0;
    background:#f4f7fb;
    font-family:Arial,Helvetica,sans-serif;
}

.container{
    width:680px;
    margin:auto;
    background:#ffffff;
    border-radius:15px;
    overflow:hidden;
    box-shadow:0 10px 35px rgba(0,0,0,.15);
}

.header{
    background:linear-gradient(90deg,#8B0000,#d32f2f);
    color:white;
    text-align:center;
    padding:35px;
}

.logo{
    font-size:32px;
    font-weight:bold;
}

.tagline{
    margin-top:8px;
    font-size:14px;
    opacity:.9;
}

.banner{
    text-align:center;
    padding:35px;
}

.icon{
    width:90px;
    height:90px;
    line-height:90px;
    margin:auto;
    border-radius:50%;
    background:#dc2626;
    color:white;
    font-size:42px;
}

.banner h2{
    color:#b91c1c;
    margin-top:20px;
}

.banner p{
    color:#555;
}

.card{
    margin:30px;
    border:1px solid #e5e7eb;
    border-radius:10px;
    overflow:hidden;
}

.card-title{
    background:#f8fafc;
    padding:18px;
    font-size:20px;
    font-weight:bold;
    color:#8B0000;
}

table{
    width:100%;
    border-collapse:collapse;
}

td{
    padding:16px;
    border-bottom:1px solid #eeeeee;
}

.label{
    font-weight:bold;
    color:#555;
}

.value{
    text-align:right;
    color:#111827;
}

.status{
    color:#dc2626;
    font-weight:bold;
    font-size:18px;
}

.notice{
    margin:30px;
    background:#fff4f4;
    border-left:6px solid #dc2626;
    padding:20px;
    border-radius:6px;
    color:#555;
}

.footer{
    background:#f8fafc;
    text-align:center;
    padding:30px;
    font-size:13px;
    color:#666;
}

.footer b{
    color:#003366;
}

</style>

</head>

<body>

<div class='container'>

<div class='header'>

<div class='logo'>
🏦 " ++ (payload.BANKNAME[0] default "N/A") ++ "
</div>

<div class='tagline'>
Secure • Trusted • Digital Banking
</div>

</div>

<div class='banner'>

<div class='icon'>
🔒
</div>

<h2>Account Successfully Deactivated</h2>

<p>

Dear <b>"
++
upper(getVal(vars.FULLNAME))
++
"</b>,

<br/><br/>

Your account has been successfully deactivated as requested.

</p>

</div>

<div class='card'>

<div class='card-title'>

Account Information

</div>

<table>

<tr>

<td class='label'>Customer Name</td>

<td class='value'>"
++
upper(getVal(vars.FULLNAME))
++
"</td>

</tr>

<tr>

<td class='label'>Bank Name</td>

<td class='value'>"
++
getVal(data.BANKNAME)
++
"</td>

</tr>

<tr>

<td class='label'>Account Number</td>

<td class='value'>"
++
getVal(data.ACCOUNTNUMBER)
++
"</td>

</tr>

<tr>

<td class='label'>Account Status</td>

<td class='value status'>
DEACTIVATED
</td>

</tr>

<tr>

<td class='label'>Effective Date</td>

<td class='value'>
"
++
(now() as String {format:"dd MMM yyyy hh:mm:ss a"})
++
"
</td>

</tr>

</table>

</div>

<div class='notice'>

<b>⚠ Security Notice</b>

<br/><br/>

If you did not request this account deactivation, please contact our
24×7 Customer Support immediately to secure your account.

</div>

<div class='footer'>

<b>Real Bank</b>

<br/><br/>

📞 Customer Care : +91 9494207062

<br/>

✉ support@realbank.com

<br/>

🌐 www.realbank.com

<br/><br/>

© 2026 Real Bank. All Rights Reserved.

<br/><br/>

This is a system-generated email. Please do not reply.

</div>

</div>

</body>

</html>"]
